-- Schema for sm_hostel_rooms ---
CREATE TABLE `sm_hostel_rooms` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `hostel_id` bigint unsigned NOT NULL,
  `room_no` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `room_type` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'single, double, dormitory',
  `capacity` int NOT NULL DEFAULT '1',
  `floor` int NOT NULL DEFAULT '0',
  `fee_per_month` decimal(10,2) NOT NULL DEFAULT '0.00',
  `amenities` text COLLATE utf8mb4_unicode_ci COMMENT 'JSON list',
  `status` enum('available','occupied','maintenance','reserved') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'available',
  `school_id` bigint unsigned NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `sm_hostel_rooms_hostel_id_foreign` (`hostel_id`),
  CONSTRAINT `sm_hostel_rooms_hostel_id_foreign` FOREIGN KEY (`hostel_id`) REFERENCES `sm_hostels` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
