INSERT INTO `sm_news` VALUES (31,'Digital Transformation in Education: SAC EDU Paving the Way',6,1,'public/uploads/news/news1.jpg',NULL,'<div class=\'news-body\' style=\'font-size: 16px; line-height: 1.6;\'>\r\n                                            <p class=\'lead\'>SAC EDU is leading the charge in digital transformation, revolutionizing the way education is delivered. With cloud-based solutions and real-time data analytics, SAC EDU enables institutions to streamline operations, enhance student engagement, and foster a culture of innovation. This shift not only modernizes the classroom but also prepares students for a digital-first world.</p>\r\n                                            <div class=\'text-muted\'>Learn more about our journey to enhance education for all.</div>\r\n                                         </div>','2019-06-02',0,1,1,0,0,'1','2026-05-15 06:53:09','2026-05-15 06:53:09',1,1,1,1,1),(32,'Success Stories: How SAC EDU ERP Empowers Schools Worldwide',1,1,'public/uploads/news/news2.jpg',NULL,'<div class=\'news-body\' style=\'font-size: 16px; line-height: 1.6;\'>\r\n                                            <p class=\'lead\'>SAC EDU\'s ERP system has empowered schools across the globe to transform their administration and academic processes. By simplifying management, enhancing communication, and improving resource allocation, SAC EDU has helped schools deliver better educational experiences. Schools in multiple countries report increased efficiency, reduced costs, and greater student satisfaction thanks to this robust ERP solution.</p>\r\n                                            <div class=\'text-muted\'>Learn more about our journey to enhance education for all.</div>\r\n                                         </div>','2019-06-02',0,1,1,0,0,'2','2026-05-15 06:53:09','2026-05-15 06:53:09',1,1,1,1,1),(33,'SAC EDU Launches Enhanced Features for a Seamless School Year',1,1,'public/uploads/news/news3.jpg',NULL,'<div class=\'news-body\' style=\'font-size: 16px; line-height: 1.6;\'>\r\n                                            <p class=\'lead\'>The new features launched by SAC EDU are designed to support schools in creating a seamless and productive academic year. From updated enrollment tools and attendance tracking to advanced reporting capabilities, these enhancements offer educators and administrators more control and insight than ever before, driving educational success across all levels.</p>\r\n                                            <div class=\'text-muted\'>Learn more about our journey to enhance education for all.</div>\r\n                                         </div>','2019-06-02',0,1,1,0,0,'3','2026-05-15 06:53:09','2026-05-15 06:53:09',1,1,1,1,1),(34,'Innovations in School Management: The Future of SAC EDU',2,1,'public/uploads/news/news4.jpg',NULL,'<div class=\'news-body\' style=\'font-size: 16px; line-height: 1.6;\'>\r\n                                            <p class=\'lead\'>SAC EDU is pioneering innovations in school management, incorporating AI-driven analytics and mobile-friendly platforms that make educational management more efficient and data-informed. These advancements empower educators and administrators to manage resources, track student performance, and optimize curricula with unprecedented ease, setting new standards in education technology.</p>\r\n                                            <div class=\'text-muted\'>Learn more about our journey to enhance education for all.</div>\r\n                                         </div>','2019-06-02',0,1,1,0,0,'4','2026-05-15 06:53:09','2026-05-15 06:53:09',1,1,1,1,1),(35,'Creative Spaces: Enhancing Learning and Productivity at Home',1,1,'public/uploads/news/archive-1.jpg',NULL,'<div class=\'news-body\' style=\'font-size: 16px; line-height: 1.6;\'>\r\n                                            <p class=\'lead\'>Designing a functional and inspiring workspace can transform the way we learn and create. This organized desk setup features vibrant tools like colorful pencils, a diary for jotting down ideas, and a sleek desk lamp for focused lighting. The corkboard adds a personal touch, perfect for pinning reminders, art, or inspiration. Such setups not only encourage productivity but also make studying and working more enjoyable, proving that creativity thrives in well-designed environments.</p>\r\n                                            <div class=\'text-muted\'>Learn more about our journey to enhance education for all.</div>\r\n                                         </div>','2026-05-15',1,1,1,0,0,'1','2026-05-15 06:53:09','2026-05-15 06:53:09',1,1,1,1,1),(36,'A World of Knowledge: The Beauty of an Organized Library',0,1,'public/uploads/news/archive-2.jpg',NULL,'<div class=\'news-body\' style=\'font-size: 16px; line-height: 1.6;\'>\r\n                                            <p class=\'lead\'>A well-organized library is more than just a collection of books; it’s a gateway to endless adventures and learning. With rows of colorful book spines neatly arranged, this library inspires curiosity and exploration. Each shelf tells a story, offering readers the opportunity to dive into diverse genres, from fiction to history and science. Libraries like this create an atmosphere that fuels the imagination and fosters a lifelong love for learning.</p>\r\n                                            <div class=\'text-muted\'>Learn more about our journey to enhance education for all.</div>\r\n                                         </div>','2026-05-15',1,1,1,0,0,'2','2026-05-15 06:53:09','2026-05-15 06:53:09',1,1,1,1,1),(37,'Blending Tradition and Technology: The Book Meets the Technology',5,1,'public/uploads/news/archive-3.jpg',NULL,'<div class=\'news-body\' style=\'font-size: 16px; line-height: 1.6;\'>\r\n                                            <p class=\'lead\'>The fusion of a traditional book and a modern laptop symbolizes the harmony between timeless knowledge and cutting-edge innovation. This image captures the essence of modern education, where physical books provide depth and digital platforms offer access to limitless resources. Together, they create a balanced approach to learning, ensuring that the richness of traditional methods meets the efficiency of technology in shaping the future of education.</p>\r\n                                            <div class=\'text-muted\'>Learn more about our journey to enhance education for all.</div>\r\n                                         </div>','2026-05-15',1,1,1,0,0,'3','2026-05-15 06:53:09','2026-05-15 06:53:09',1,1,1,1,1),(38,'A Minimalist Workspace Inspiration',5,1,'public/uploads/news/archive-4.jpg',NULL,'<div class=\'news-body\' style=\'font-size: 16px; line-height: 1.6;\'>\r\n                                            <p class=\'lead\'>This setup highlights a perfect balance between functionality and aesthetics. Featuring neatly stacked books wrapped in elegant patterns, a sleek black and gold clock, and a refreshing touch of greenery from a small potted plant, it creates an inviting and productive environment. Ideal for anyone looking to stay organized while adding style to their workspace.</p>\r\n                                            <div class=\'text-muted\'>Learn more about our journey to enhance education for all.</div>\r\n                                         </div>','2026-05-15',1,1,1,0,0,'4','2026-05-15 06:53:09','2026-05-15 06:53:09',1,1,1,1,1),(39,'Late-Night Study Essentials: Creating a Cozy and Productive Space',6,1,'public/uploads/news/archive-5.jpg',NULL,'<div class=\'news-body\' style=\'font-size: 16px; line-height: 1.6;\'>\r\n                                            <p class=\'lead\'>This cozy study setup is perfect for late-night learners. With a bright desk lamp illuminating the workspace, essentials like colorful markers, a calculator, notebooks, and pens are neatly arranged for productivity. A vibrant blue backpack sits nearby, ready for the next school day. The warm orange backdrop adds a touch of energy, making studying a more inviting experience.</p>\r\n                                            <div class=\'text-muted\'>Learn more about our journey to enhance education for all.</div>\r\n                                         </div>','2026-05-15',1,1,1,0,0,'5','2026-05-15 06:53:09','2026-05-15 06:53:09',2,1,1,1,1);

