INSERT INTO `sm_news_pages` VALUES (1,NULL,NULL,'News Infix','Lisus consequat sapien metus dis urna, facilisi. Nonummy rutrum eu lacinia platea a, ipsum parturient, orci tristique. Nisi diam natoque.','Under Graduate Education','SAC has all in one place. You’ll find everything what you are looking into education management system software. We care! User will never bothered in our real eye catchy user friendly UI & UX  Interface design. You know! Smart Idea always comes to well planners. And Our SAC is Smart for its Well Documentation. Explore in new support world! It’s now faster & quicker. You’ll find us on Support Ticket, Email, Skype, WhatsApp.','public/uploads/about_page/about.jpg','public/uploads/about_page/about-img.jpg','Learn More News ','news-page',1,1,1,1);

